mapper.select:
SELECT COUNT(*)
FROM SCOTT.post_bookmarks
WHERE account_id = #{accountId, jdbcType=NUMERIC}
  AND post_id    = #{postId, jdbcType=NUMERIC}

mapper.delete:
DELETE FROM SCOTT.post_bookmarks
WHERE account_id = #{accountId, jdbcType=NUMERIC}
  AND post_id    = #{postId, jdbcType=NUMERIC}

mapper.select:
SELECT COUNT(*) FROM SCOTT.post_bookmarks pb JOIN SCOTT.vw_posts_with_counts v ON v.post_id = pb.post_id WHERE pb.account_id = #{accountId, jdbcType=NUMERIC}
AND ( v.content LIKE '%' || #{q} || '%' OR EXISTS ( SELECT 1 FROM SCOTT.tag_links tl JOIN SCOTT.tags t ON t.tag_id = tl.tag_id WHERE tl.post_id = v.post_id AND t.tag_text LIKE '%' || REPLACE(#{q}, '#', '') || '%' ) OR v.nickname LIKE '%' || #{q} || '%' OR v.handle LIKE '%' || REPLACE(#{q}, '@', '') || '%' OR ( REPLACE(v.nickname, ' ', '') || '@' || REPLACE(REPLACE(v.handle, '@', ''), ' ', '') ) LIKE '%' || REPLACE(REPLACE(#{q}, ' ', ''), '@@', '@') || '%'
)
